parameters.jsCode:
const raw = $input.item.json.text || $input.item.json.output || '';
const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const parsed = JSON.parse(cleaned);
const engagementId = $('Prepare Prompt').first().json.engagement_id;
return { json: { engagement_id: engagementId, structured_brief: parsed } };
